import json
from google.cloud import functions

def handler(request):
    # validate request
    if not request.headers.get("X-Webhook-Event"):
        return "Invalid request", 400
    
    # handle webhook event
    try:
        data = json.loads(request.body)
        # process payment information
        print(f"Received payment for {data['amount']} {data['currency']}")
    except ValueError:
        return "Invalid request", 400
    
    # send response
    return "Payment received successfully", 200